#include <vector>
#include <string>
#include <regex>
#include <algorithm>

using namespace std;

vector<string> solve(vector<string> code, vector<string> businessLine, vector<bool> isActive) {
    regex codeRegex("^[a-zA-Z0-9_]+$");
    vector<pair<string, string>> validCoupons;

    for (size_t i = 0; i < code.size(); ++i) {
        if (code[i].empty()) continue;
        if (!regex_match(code[i], codeRegex)) continue;

        string bl = businessLine[i];
        if (bl != "electronics" && bl != "grocery" && bl != "pharmacy" && bl != "restaurant") continue;

        if (!isActive[i]) continue;

        validCoupons.push_back({bl, code[i]});
    }

    sort(validCoupons.begin(), validCoupons.end(), [](const pair<string, string>& a, const pair<string, string>& b) {
        int orderA = 0;
        if (a.first == "electronics") orderA = 0;
        else if (a.first == "grocery") orderA = 1;
        else if (a.first == "pharmacy") orderA = 2;
        else if (a.first == "restaurant") orderA = 3;

        int orderB = 0;
        if (b.first == "electronics") orderB = 0;
        else if (b.first == "grocery") orderB = 1;
        else if (b.first == "pharmacy") orderB = 2;
        else if (b.first == "restaurant") orderB = 3;

        if (orderA != orderB) return orderA < orderB;
        return a.second < b.second;
    });

    vector<string> result;
    for (const auto& p : validCoupons) {
        result.push_back(p.second);
    }
    return result;
}

