-module(solution).
-export([solve/3]).

solve(Code, BusinessLine, IsActive) ->
    ValidCoupons = [ {BL, CodeStr} || {CodeStr, BL, IsActive} <- lists:zip3(Code, BusinessLine, IsActive), check_coupon(CodeStr, BL, IsActive) ],
    Sorted = lists:sort(fun(A, B) -> comparator(A, B) end, ValidCoupons),
    [Code || {_, Code} <- Sorted].

check_coupon(CodeStr, BL, IsActive) ->
    not string:is_empty(CodeStr) andalso
    re:run(CodeStr, "^\\w+$", [global, {return, true}]) == {match, _} andalso
    lists:member(BL, ["electronics", "grocery", "pharmacy", "restaurant"]) andalso
    IsActive.

comparator({BLA, CodeA}, {BLB, CodeB}) ->
    PriorityA = case BLA of
        "electronics" -> 0;
        "grocery" -> 1;
        "pharmacy" -> 2;
        "restaurant" -> 3
    end,
    PriorityB = case BLB of
        "electronics" -> 0;
        "grocery" -> 1;
        "pharmacy" -> 2;
        "restaurant" -> 3
    end,
    if
        PriorityA < PriorityB -> true;
        PriorityA > PriorityB -> false;
        true -> CodeA < CodeB
    end.
```

